from collections import defaultdict

def detect_cycles(graph, max_iterations=50):
    state_visits = defaultdict(int)

    @graph.before('agent')
    def cycle_monitor(state):
        current_path = state.get('path', [])
        if len(current_path) > max_iterations:
            raise ValueError(f"Cycle detected: {current_path[-10:]}")
        return state

    return graph

from typing import TypedDict, Any
from langgraph.graph.message import add_messages

class ValidState(TypedDict):
    messages: list
    data: dict
    version: int

class StateCorruptionGuard:
    def __init__(self):
        self.schema_version = 1

    def validate_merge(self, state: ValidState) -> ValidState:
        if 'version' not in state or state['version'] != self.schema_version:
            raise ValueError(f"State corruption detected: version {state.get('version')} != {self.schema_version}")
        if len(set(msg.id for msg in state['messages'])) != len(state['messages']):
            raise ValueError("Duplicate message IDs detected - merge corruption")
        return state

