from typing import TypedDict, List
from langgraph.graph import StateGraph

class ConflictFreeState(TypedDict):
    shared_data: dict
    branch_results: List[dict]

class AtomicMerger:
    def merge_parallel(self, state: ConflictFreeState) -> ConflictFreeState:
        # Last-write-wins with validation
        final_data = state['shared_data'].copy()
        for branch in state['branch_results']:
            for key, value in branch.items():
                if isinstance(value, dict):  # Deep merge
                    final_data.setdefault(key, {}).update(value)
                else:
                    final_data[key] = value
        state['shared_data'] = final_data
        state['branch_results'] = []
        return state

