from langgraph.checkpoint.base import BaseCheckpointSaver
from typing import Any, Dict

class VersionedCheckpointer(BaseCheckpointSaver):
    def __init__(self, inner):
        self.inner = inner
        self.schema_version = 2

    def put(self, config, checkpoint: bytes, snapshot: bytes = None):
        # Wrap with version metadata
        versioned = {
            'version': self.schema_version,
            'checkpoint': checkpoint,
            'snapshot': snapshot
        }
        return self.inner.put(config, pickle.dumps(versioned))

    def get(self, config) -> Dict[str, Any]:
        data = pickle.loads(self.inner.get(config)['checkpoint'])
        if data['version'] != self.schema_version:
            data = self.migrate(data)
        return data

